mapper.select:
SELECT FROM support_sessions ss JOIN users u ON ss.user_id = u.id LEFT JOIN support_messages sm ON ss.id = sm.session_id
ss.status = #{status}
GROUP BY ss.id, ss.user_id, ss.assigned_admin_id, ss.status, ss.last_message, ss.last_message_at, ss.created_at, ss.updated_at, u.username ORDER BY ss.updated_at DESC
